func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state for CSRF protection
	stateBytes := make([]byte, 16)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", err
	}
	state := hex.EncodeToString(stateBytes)

	// Validate the redirect path is not empty
	if redirectPath == "" {
		return "", errors.New("redirect path cannot be empty")
	}

	// Parse the redirect path to validate it
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect path format")
