	}
	// Check for reverse proxy headers (e.g., behind nginx, load balancer)
	if proto := r.Header.Get("X-Forwarded-Proto"); proto != "" {
		scheme = proto
	}

	fullRedirectURL := scheme + "://" + r.Host + redirectPath

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = fullRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation with appropriate expiration
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		Expires:  time.Now().Add(10 * time.Minute),
	})

	return authURL, nil
}

