var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// allowedRedirectHosts defines the whitelist of allowed hosts for redirect URLs
var allowedRedirectHosts = map[string]bool{
	"yourapp.com":     true,
	"www.yourapp.com": true,
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state to prevent CSRF attacks
	stateBytes := make([]byte, 16)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", errors.New("failed to generate secure state")
	}
	state := hex.EncodeToString(stateBytes)

	// Validate and build the redirect URL to prevent open redirect attacks
	validatedRedirectURL, err := validateRedirectURL(redirectPath)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// validateRedirectURL validates the redirect path to prevent open redirect attacks.
// It only allows relative paths or absolute URLs with whitelisted hosts.
func validateRedirectURL(redirectPath string) (string, error) {
	// If no redirect path provided, use the default configured URL
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Parse the redirect path
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL format")
	}

	// If it's a relative path (not absolute), construct full URL from base
	if !parsedURL.IsAbs() {
		// Validate that the path starts with / to prevent scheme-relative URLs
		if len(redirectPath) == 0 || redirectPath[0] != '/' {
			return "", errors.New("relative redirect path must start with /")
		}

		// Construct full URL from the base redirect URL
		baseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return "", errors.New("invalid base redirect URL configuration")
		}
		baseURL.Path = redirectPath
		return baseURL.String(), nil
	}

	// For absolute URLs, validate the host is in the whitelist
	if !allowedRedirectHosts[parsedURL.Host] {
		return "", errors.New("redirect URL host is not allowed")
	}

	// Ensure the scheme is HTTPS for security
	if parsedURL.Scheme != "https" {
		return "", errors.New("redirect URL must use HTTPS")
	}

	return redirectPath, nil
}

