	"https://yourapp.com/callback":       true,
	"https://yourapp.com/auth/callback":  true,
	"https://yourapp.com/login/callback": true,
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state to prevent CSRF attacks
	stateBytes := make([]byte, 32)
	if _, err := rand.Read(stateBytes); err != nil {
		return "", err
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Validate and determine the redirect URL
	redirectURL, err := validateRedirectURL(redirectPath)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation (CSRF protection)
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// validateRedirectURL validates the redirect URL to prevent open redirect attacks
func validateRedirectURL(redirectPath string) (string, error) {
	// Use default if empty
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Security: Reject scheme-relative URLs (e.g., //evil.com)
	// These could bypass host validation and redirect to external domains
	if strings.HasPrefix(redirectPath, "//") {
		return "", errors.New("scheme-relative URLs are not allowed")
	}

