	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL format")
	}

	if parsedURL.IsAbs() {
		// Absolute URL: must be in whitelist
		if !allowedRedirectURLs[redirectPath] {
			return "", errors.New("absolute redirect URL not in whitelist")
		}
		return redirectPath, nil
	}

