// callbackHandler handles the OAuth callback after user authorization
func callbackHandler(w http.ResponseWriter, r *http.Request) {
	// Verify the state to prevent CSRF attacks
	state := r.URL.Query().Get("state")
	cookie, err := r.Cookie("oauth_state")
	if err != nil || cookie.Value != state {
		http.Error(w, "Invalid state parameter - possible CSRF attack", http.StatusBadRequest)
		return
	}

	// Clear the state cookie after verification
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
	})

	// Get the authorization code from the callback
	code := r.URL.Query().Get("code")
	if code == "" {
		http.Error(w, "Authorization code not found", http.StatusBadRequest)
		return
	}

	// Exchange the authorization code for an access token
	token, err := OAuthConfig.Exchange(r.Context(), code)
	if err != nil {
		http.Error(w, fmt.Sprintf("Failed to exchange token: %v", err), http.StatusInternalServerError)
		return
	}

	// Return success with token information (in production, you'd create a session)
	fmt.Fprintf(w, "OAuth2 authentication successful!\n")
	fmt.Fprintf(w, "Access Token: %s\n", token.AccessToken)
	fmt.Fprintf(w, "Token Type: %s\n", token.TokenType)
	if token.RefreshToken != "" {
		fmt.Fprintf(w, "Refresh Token: %s\n", token.RefreshToken)
	}
}

func main() {
	// Set up HTTP routes
	http.HandleFunc("/login", loginHandler)
	http.HandleFunc("/callback", callbackHandler)

	// Start the server
	fmt.Println("OAuth2 server starting on :8080")
	fmt.Println("Visit http://localhost:8080/login to start OAuth flow")
	fmt.Println("Or http://localhost:8080/login?redirect_path=/custom/callback for custom redirect")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

